use Phoenix.Controller
use SweetXml

# Define the endpoint
post "/soap", fn(conn) ->
  # Parse XML request body
  xml = SweetXml.parse!(conn.body)

  # Extract data using xpath()
  name = xml.xpath("/soapenv:Envelope/soapenv:Body/ns:Request/ns:Name").text

  # Respond with the parsed data
  {:ok, conn, %{}, %{name: name}}
end